#include <bits/stdc++.h>
using namespace std;
const int N=200005,mod=10007;
int n,w[N],ans,maxx;
vector<int> g[N];
int main()
{
    cin>>n;
    for(int i=1;i<n;i++)
    {
        int u,v;
        cin>>u>>v;
        g[u].push_back(v);
        g[v].push_back(u);
    }
    for(int i=1;i<=n;i++)
    {
        cin>>w[i];
    }
    for(int i=1;i<=n;i++)
    {
        int mx1=0,mx2=0,t1=0,t2=0;
        for(int j=0;j<g[i].size();j++)
        {
            int v=g[i][j];
            if(w[v]>mx1) mx2=mx1,mx1=w[v];
            else if(w[v]>mx2) mx2=w[v];
            t1+=w[v],t2+=(w[v]*w[v])%mod;
            t1%=mod;
            t2%=mod;
        }
        maxx=max(maxx,mx1*mx2);
        ans=(ans+t1*t1+mod-t2)%mod;
    }
    cout<<maxx<<" "<<ans;
    return 0;
}
